#include <stdio.h>

int next(int x) {
    int k = 0;
    while (x > 1) {
        x /= 2;
        k++;
    }
    return k;
}

int st(int x) {
    int k = 1;
    for (int i = 0; i < x; i++) {
        k *= 2;
    }
    return k;
}

int main() {
    int n, b, p;
    scanf("%d %d %d", &n, &b, &p);
    int ans = 0;
    int ll = n * p;
    while (n != 1) {
        int k = st(next(n));
        n -= k;
        n += (k / 2);
        ans += (k / 2) * 2 * b;
        ans += (k / 2);
    }
    printf("%d\n", ans);
    printf("%d\n", ll);
    return 0;
}
